{
  "command": "sqlite3 '/workspace/DataAgentBench/query_stockmarket/query_dataset/stockinfo_query.db' \"SELECT DISTINCT \\\"Listing Exchange\\\", \\\"Market Category\\\" FROM stockinfo LIMIT 20;\"",
  "description": "Check listing exchanges and market categories"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_stockmarket/query_dataset/stockinfo_query.db' \"SELECT COUNT(*) FROM stockinfo WHERE \\\"Market Category\\\" = 'S';\"",
  "description": "Count NASDAQ Capital Market stocks"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_stockmarket/query_dataset/stockinfo_query.db' \"SELECT Symbol, \\\"Company Description\\\" FROM stockinfo WHERE \\\"Market Category\\\" = 'S' LIMIT 10;\"",
  "description": "Sample symbols"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_stockmarket/query_dataset/stockinfo_query.db' \"SELECT Symbol FROM stockinfo WHERE \\\"Market Category\\\" = 'S';\" > /tmp/nasdaq_s_symbols.txt\nwc -l /tmp/nasdaq_s_symbols.txt\nhead -20 /tmp/nasdaq_s_symbols.txt",
  "description": "Get all NASDAQ Capital Market symbols"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_stockmarket/query_dataset/stocktrade_query.db' -readonly \"SELECT table_name FROM information_schema.tables LIMIT 5;\"",
  "description": "Check table structure in DuckDB"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_stockmarket/query_dataset/stocktrade_query.db' -readonly -csv \"SELECT table_name FROM information_schema.tables;\" > /tmp/all_tables.csv\nwc -l /tmp/all_tables.csv",
  "description": "Get all tables csv"
}
